import { describe, it, beforeAll, afterAll, beforeEach } from "vitest";
import assert from "node:assert";
import fs from "node:fs";
import os from "node:os";
import path from "node:path";
import { setProjectRoot, bobbitConfigDir, bobbitStateDir } from "../../src/server/bobbit-dir.js";
import { isSetupComplete } from "../../src/server/setup-status.js";
import { withEnv } from "../harness/with-env.js";

// This suite resolves bobbit dirs from an explicit project root, so BOBBIT_DIR /
// BOBBIT_PI_DIR must be unset while it runs. Under isolate:false a prior file in
// the fork (e.g. the gateway fixture) may have BOBBIT_DIR set, so every env-
// reading call is wrapped in withEnv(CLEARED, ...) which restores on exit.
const CLEARED = { BOBBIT_DIR: undefined, BOBBIT_PI_DIR: undefined };

describe("isSetupComplete", () => {
	let tmpDir: string;

	beforeAll(() => {
		tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "is-setup-complete-"));
		setProjectRoot(tmpDir);
	});

	afterAll(() => {
		fs.rmSync(tmpDir, { recursive: true, force: true });
	});

	beforeEach(() => withEnv(CLEARED, () => {
		// Reset filesystem state between tests
		const stateDir = bobbitStateDir();
		const sentinel = path.join(stateDir, "setup-complete");
		const userPrompt = path.join(bobbitConfigDir(), "system-prompt.md");
		try { fs.rmSync(sentinel); } catch {}
		try { fs.rmSync(userPrompt); } catch {}
	}));

	it("returns false when neither sentinel nor user system-prompt.md exists", () => withEnv(CLEARED, () => {
		assert.strictEqual(isSetupComplete(), false);
	}));

	it("returns true when only the sentinel file exists", () => withEnv(CLEARED, () => {
		const stateDir = bobbitStateDir();
		fs.mkdirSync(stateDir, { recursive: true });
		fs.writeFileSync(path.join(stateDir, "setup-complete"), "");
		assert.strictEqual(isSetupComplete(), true);
	}));

	it("returns true when only the user system-prompt.md exists", () => withEnv(CLEARED, () => {
		const cfg = bobbitConfigDir();
		fs.mkdirSync(cfg, { recursive: true });
		fs.writeFileSync(path.join(cfg, "system-prompt.md"), "anything\n");
		assert.strictEqual(isSetupComplete(), true);
	}));

	it("returns true when both exist", () => withEnv(CLEARED, () => {
		const stateDir = bobbitStateDir();
		const cfg = bobbitConfigDir();
		fs.mkdirSync(stateDir, { recursive: true });
		fs.mkdirSync(cfg, { recursive: true });
		fs.writeFileSync(path.join(stateDir, "setup-complete"), "");
		fs.writeFileSync(path.join(cfg, "system-prompt.md"), "anything\n");
		assert.strictEqual(isSetupComplete(), true);
	}));
});
